var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"칫……!","JPN":"ちっ……！","ENG":"Tsk!","TWN":"嗟…！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"야, 옷 찢어졌잖아! 너 이거 어떻게 배상할 거야?!","JPN":"ちょっと、服が破れたじゃない！　あんたたちこれどうしてくれるの！？","ENG":"Hey, you ripped my clothes off! You’ll have to pay for this!","TWN":"喂，我的衣服都破了！ 你要怎麼賠？！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"이상하네. 생김새는 징그러운데 위험하게 느껴지지가 않아.","JPN":"おかしい。見た目は気持ち悪いけど殺気を感じられない。","ENG":"Weird. They look disgusting, but I don’t feel like they’re dangerous.","TWN":"真奇怪，長得很噁心，卻感覺不到危險性。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"하는 짓도 꼭 공격하려는 게 아니라 겁이라도 주는 것처럼…….","JPN":"攻撃しようとするわけではなく、まるで脅すだけの……","ENG":"Their attacks are not threatening, either. It’s like they’re just trying to scare us away...","TWN":"好像只是在裝腔作勢嚇唬人而已……"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"뭐, 뭘 그렇게 빤히 쳐다 봐? 내 얼굴에 뭐 묻었어?","JPN":"何じっと見てるの？　なんか顔についてる？","ENG":"W-what are you looking at? Something on my face?","TWN":"幹嘛？幹嘛一直盯著我看？我臉上有沾到東西嗎？"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"리코리스, 메이드복 안에 그런 걸 입고 다녔습니까?","JPN":"リコリス、メイド服の中にそんな服を着ていたのですか？","ENG":"Lycoris, why are you wearing that under your maid uniform?","TWN":"莉克麗絲，你在女僕裝裡還穿那種東西嗎？"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"이, 이거 말이야?! 그냥 예쁜 해변이 있다길래 놀 시간도 있지 않을까 하고……!","JPN":"こ、これ！？　キ、キレイなビーチがあると聞いて、もしかしたら遊ぶ時間もあるんじゃないかと思って……！","ENG":"W-what, this?! I just thought... since we’re at a beautiful beach, maybe we could spend some time having fun...","TWN":"你說這個？！我想說是在漂亮的海灘嘛，說不定有時間可以放風……！"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그렇다고 역시 남들 앞에선 조금 부끄럽달까…….","JPN":"でもやっぱり人前では少し恥ずかしいというか……","ENG":"But still, it’s a bit embarrassing to wear it in front of people...","TWN":"不過在別人面前穿成這樣，還真是有點害羞呢………"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"노답이네요.","JPN":"あたおかですね。","ENG":"You’re hopeless.","TWN":"無言。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"나 릴리는 리코리스에게 실망했다, 입니다. 다 큰 사람이 모네처럼 머리에 놀 생각뿐이군요.","JPN":"私、リリーはリコリスに失望したぞ、です。立派な大人が遊ぶことばかり考えて。","ENG":"I, Lily, am disappointed in you, Lycoris. You’re a grown-up, and all you can think of is having fun, just like Mone.","TWN":"莉莉對莉克麗絲太失望了，都這麼大了，還跟莫妮一樣整天只想著玩。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"잠깐만! 그러는 넌 처음부터 수영복 차림이었잖아!","JPN":"ちょっと待って！　そういうあんたこそ、最初から水着姿だったでしょ！","ENG":"But you’ve been wearing the swimsuit the whole time!","TWN":"先等等！你還有敢說我，你自己可是一開始就穿上泳裝欸！"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"이건 현지에 완벽히 녹아들기 위한 위장입니다. 못 알아채는 걸 보면 리코리스도 <color=#ffd34c>꼰대</color>군요.","JPN":"これは現地に完全に溶け込むための偽装です。分かってくれないなんて、リコリスも<color=#ffd34c>草</color>ですね。","ENG":"I’m only wearing this to blend in with locals. You are such a <color=#ffd34c>boomer</color> not to realize that, Lycoris.","TWN":"我這身偽裝是為了要完美融入當地，你竟然不懂我的用意，你真是<color=#ffd34c>心胸狹隘</color>。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그럴 때 쓰는 말 아니거든…….","JPN":"言葉の使い方間違ってるわよ……","ENG":"That’s not the right term for this occasion...","TWN":"你不要亂用成語好嗎…"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"에휴, 그나저나 이제 다 텄네.","JPN":"はあ、というか、もうオワコンね。","ENG":"*Sigh* Anyway, it’s a bust.","TWN":"算了，總之GG了啦！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"무슨 뜻이죠?","JPN":"どういう意味ですか？","ENG":"What do you mean?","TWN":"這什麼意思？"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"망했다는 뜻이야.","JPN":"失敗ってこと。","ENG":"Meaning we failed.","TWN":"就是完蛋的意思。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};